// MARK: - Security Manager

class SecurityManager {
    static let shared = SecurityManager()
    private let keychain = KeychainManager()
    
    func encryptData(_ data: Data) throws -> Data {
        let key = SymmetricKey(size: .bits256)
        let sealedBox = try AES.GCM.seal(data, using: key)
        return sealedBox.combined!
    }
    
    func decryptData(_ encryptedData: Data, key: SymmetricKey) throws -> Data {
        let sealedBox = try AES.GCM.SealedBox(combined: encryptedData)
        return try AES.GCM.open(sealedBox, using: key)
    }
    
    func generateSignature(for data: Data, privateKey: String) -> String {
        let key = SymmetricKey(data: privateKey.data(using: .utf8)!)
        let signature = HMAC<SHA256>.authenticationCode(for: data, using: key)
        return Data(signature).base64EncodedString()
    }
    
    func storeAPIKey(_ key: String, for service: String) {
        keychain.save(key, for: service)
    }
    
    func retrieveAPIKey(for service: String) -> String? {
        return keychain.load(for: service)
    }
}

class KeychainManager {
    func save(_ value: String, for key: String) {
        let data = value.data(using: .utf8)!
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: data
        ]
        SecItemDelete(query as CFDictionary)
        SecItemAdd(query as CFDictionary, nil)
    }
    
    func load(for key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true
        ]
        var result: AnyObject?
        SecItemCopyMatching(query as CFDictionary, &result)
        guard let data = result as? Data else { return nil }
        return String(data: data, encoding: .utf8)
    }
}

// MARK: - Network Manager

class NetworkManager {
    static let shared = NetworkManager()
    private let baseURL = "https://api.tradingplatform.com/v1"
    private let session: URLSession
    private var cancellables = Set<AnyCancellable>()
    
    init() {
        let configuration = URLSessionConfiguration.default
        configuration.timeoutIntervalForRequest = 30
        configuration.requestCachePolicy = .reloadIgnoringLocalCacheData
        self.session = URLSession(configuration: configuration)
    }
    
    func request<T: Codable>(
        endpoint: String,
        method: String = "GET",
        body: Data? = nil,
        authenticated: Bool = true
    ) -> AnyPublisher<T, Error> {
        guard let url = URL(string: baseURL + endpoint) else {
            return Fail(error: URLError(.badURL)).eraseToAnyPublisher()
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        if authenticated {
            if let apiKey = SecurityManager.shared.retrieveAPIKey(for: "trading_api_key") {
                request.setValue("Bearer \(apiKey)", forHTTPHeaderField: "Authorization")
            }
        }
        
        if let body = body {
            request.httpBody = body
            let signature = SecurityManager.shared.generateSignature(for: body, privateKey: "secret_key")
            request.setValue(signature, forHTTPHeaderField: "X-Signature")
        }
        
        return session.dataTaskPublisher(for: request)
            .tryMap { data, response -> Data in
                guard let httpResponse = response as? HTTPURLResponse else {
                    throw URLError(.badServerResponse)
                }
                
                guard (200...299).contains(httpResponse.statusCode) else {
                    throw URLError(.init(rawValue: httpResponse.statusCode))
                }
                
                return data
            }
            .decode(type: T.self, decoder: JSONDecoder())
            .receive(on: DispatchQueue.main)
            .eraseToAnyPublisher()
    }
}

// MARK: - WebSocket Manager

class WebSocketManager: NSObject {
    static let shared = WebSocketManager()
    private var webSocket: URLSessionWebSocketTask?
    private let session = URLSession(configuration: .default)
    var onMarketDataReceived: ((MarketData) -> Void)?
    
    func connect() {
        guard let url = URL(string: "wss://stream.tradingplatform.com/market") else { return }
        webSocket = session.webSocketTask(with: url)
        webSocket?.resume()
        receiveMessage()
    }
    
    func disconnect() {
        webSocket?.cancel(with: .goingAway, reason: nil)
    }
    
    func subscribe(to symbols: [String]) {
        let subscription = ["action": "subscribe", "symbols": symbols]
        if let data = try? JSONEncoder().encode(subscription),
           let string = String(data: data, encoding: .utf8) {
            send(message: string)
        }
    }
    
    private func send(message: String) {
        let message = URLSessionWebSocketTask.Message.string(message)
        webSocket?.send(message) { error in
            if let error = error {
                print("WebSocket send error: \(error)")
            }
        }
    }
    
    private func receiveMessage() {
        webSocket?.receive { [weak self] result in
            switch result {
            case .success(let message):
                switch message {
                case .string(let text):
                    self?.handleMessage(text)
                case .data(let data):
                    if let text = String(data: data, encoding: .utf8) {
                        self?.handleMessage(text)
                    }
                @unknown default:
                    break
                }
                self?.receiveMessage()
            case .failure(let error):
                print("WebSocket receive error: \(error)")
            }
        }
    }
    
    private func handleMessage(_ text: String) {
        guard let data = text.data(using: .utf8),
              let marketData = try? JSONDecoder().decode(MarketData.self, from: data) else {
            return
        }
        onMarketDataReceived?(marketData)
    }
}

